INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间卫生干净，环境不错，服务贴心', '房间卫生干净，环境不错，服务贴心', '2024-06-09', 5, '[''卫生状况'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235x12000eecm3yq22E3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231p12000eecxw256C9B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店地处广州市中心的位置，酒店大气，环境优美，服务人员热情，主动。床铺舒', '广州花园酒店地处广州市中心的位置，酒店大气，环境优美，服务人员热情，主动。床铺舒适，超性价比的价格值的点赞', '2024-03-30', 5, '[''整体满意度'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0231x12000djiqxf3126B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '办入住的时候 立即享受了房间升级的优惠， 花了很少的钱 入住了新装修的套房， 漂', '办入住的时候 立即享受了房间升级的优惠， 花了很少的钱 入住了新装修的套房， 漂亮舒适整洁， 服务是全世界最棒的！ 
还和朋友一起下午茶 ， 遇到了很多美女网红在拍照打卡， 虽然我是个女的 感觉也挺养眼！ 金碧辉煌的大堂 ， 非常契合岭南文化的韵味！', '2024-01-17', 5, '[''前台服务'', ''整体满意度'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0230c12000cykdb1iBD54_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234a12000cyks5ba5AD0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000cykrk0n2274_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '因为团了两份一晚的套餐，忘记复制了，竟然要写两遍哈哈??我不想写两遍～这篇就看图', '因为团了两份一晚的套餐，忘记复制了，竟然要写两遍哈哈??我不想写两遍～这篇就看图说话吧
图1花园瀑布，好看的值得一逛里面还有很多小景点出片的，就有种影楼拍照的密集布景～很嗲
图2每天晚上回去会有小甜品，因为回去都太晚了～所以也不知道是下午茶还是夜宵～我估计应该是下午茶？哈哈
图3??是酒店2楼荔湾艇的奶茶！虽然不便宜～和茶位费一样贵～但真的很可爱～很别致的小狮子～我建议茶可以不喝～小狮子一定要点哦～对了，吃到一半会有人说书～蛮有意思的', '2024-01-25', 4, '[''餐饮设施'', ''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236z12000d1fb1qaB062_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000d1f6grc8181_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230v12000d1f9nyk1F6D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '绝对是五星的性价比，服务超好，内部环境很干净', '绝对是五星的性价比，服务超好，内部环境很干净', '2024-05-24', 5, '[''性价比'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235612000e56io4903D4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c12000e56b84x8177_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000e56vphqB6E8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务周到，房间整洁，开心之旅！', '服务周到，房间整洁，开心之旅！', '2024-06-08', 5, '[''整体满意度'', ''客房服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233812000edryn8e80CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000edrybs08CC6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000edryyld0851_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务周到，宾至如归', '酒店服务周到，宾至如归', '2024-06-08', 5, '[''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230b12000edry10142E6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000edrx8157DC3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233112000edrybmzC955_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_tex