环境：很好
服务：很好！', '2024-02-18', 5, '[''房间设施'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230q12000d8i6vd4AE8C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000d8i6i0m4E75_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234w12000d8i6zgaEBC7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '因为觉得住的还挺好所以续房一天，酒店正好重新装修一部分房间，让我们搬到粤韵房了，', '因为觉得住的还挺好所以续房一天，酒店正好重新装修一部分房间，让我们搬到粤韵房了，这个房间更新一些，床也更舒适，酒店早餐还不错，还赠送了水果，小小瑕疵就是退房把车开上来装行李的时候，我们打算停在门口装，礼宾部外面的接待员让我停到对面的专用车位，绕了一圈开过去之后我请其他的服务员把行李车送到车子旁边，他张嘴一句，你能把车开到门口吗？??，所以不知道到底要在哪里装，有没有一个执行标准呢？小小瑕疵不掩玉，对酒店其他服务还都是很满意的。', '2023-12-24', 5, '[''房间设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233e12000cseympoBFBE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232m12000cses5s878E5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000csf1umgF6F1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000cseu3w32483_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231z12000cseitsd4534_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235512000cseu3pfBF6B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '细致服务，满意', '细致服务，满意', '2024-06-03', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233m324x8v34es8cDDC5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231z324x8v34tsla6009_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233s324x8v3r6zj92291_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意的酒店，入住以来处处满意，房间有些旧，但能满足需求，服务人员入微亲切，那', '非常满意的酒店，入住以来处处满意，房间有些旧，但能满足需求，服务人员入微亲切，那么冷的天电梯小姐穿的单薄跑到室外指引我们停车库方向。还帮我们升级了红棉双床房，除了床有些软，都很喜欢。', '2023-12-22', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235a12000cs68levA63B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000cs6cjt2BEB4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231g12000cs651f40F6D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000cs6eg3fEC84_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232512000cs6eg3hD001_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000cs6426x72BD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000cs6a49lAA3A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236i12000cs65xlm65E5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235x12000cs68966EEA9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：比较怀旧复古小香港的那种风格', '设施：比较怀旧复古小香港的那种风格
环境：挺舒服的
卫生：干净整洁

服务：很好总体来说  问了意见后 我建议水太少 马上增加了矿泉水数量 很好', '2024-01-27', 5, '[''整体满意度'', ''客房服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235h12000d23onf5195A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235712000d23uj5g3C0E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大堂富丽堂皇，像一座艺术殿堂，房间干净卫生整齐，服务态度好。瀑布餐厅漂亮值得打卡', '大堂富丽堂皇，像一座艺术殿堂，房间干净卫生整齐，服务态度好。瀑布餐厅漂亮值得打卡，四楼酒店博物馆讲述了中国酒店的发展史', '2024-02-13', 5, '[''整体满意度'', ''卫生状况'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232f12000d6u6fhs2768_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234l12000d6u22r564DA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236712000d6u1iaw5B00_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', 'Joyce 为我们免费升级的套房，?非常不错，人也漂亮，英语流利', 'Joyce 为我们免费升级的套房，?非常不错，人也漂亮，英语流利', '2024-03-25', 5, '[''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231712000di2k5bo6032_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235712000di2m1y36243_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000di2uqdtCEBE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236512000di2e70d2825_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231212000di2mv6lCB16_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000di2foi3CA64_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q12000di2mm0rB63E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000di28k7gE246_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '没有住到自己想住的房间（原已订房）办理入住时，碰到一个业务不熟的服务员（三间房办', '没有住到自己想住的房间（原已订房）办理入住时，碰到一个业务不熟的服务员（三间房办理了一个多小时）但还是没有办理完整的入住手续，给我们后续入住带来了很大的麻烦（餐饮、房卡）', '2023-12-25', 3, '[''前台服务'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0233s12000cspnj4oC066_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000cspxe751FDC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w12000cspqs7u48CF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '上次住感觉还可以，这次真的太差了尤其是卫生真的好差，房间有股浓臭味，地毯也好脏。', '上次住感觉还可以，这次真的太差了尤其是卫生真的好差，房间有股浓臭味，地毯也好脏。一般在哪里酒店住套房房间都会准备好水果，楼下的工程噪音夜晚通宵吵得没办法睡觉。大堂穿闪片旗袍的礼仪有个女儿脾气太拽了一点礼貌没有。', '2023-12-06', 2, '[''卫生状况'', ''安静程度'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231p12000couxerd3767_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '停车很方便，有充电桩，设施服务完善，交通方便，客房部徐经理贴心的赠送了水果和儿童', '停车很方便，有充电桩，设施服务完善，交通方便，客房部徐经理贴心的赠送了水果和儿童洗漱用品.', '2025-02-10', 5, '[''公共设施'', ''交通便利性'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231912000ig0v6r64CC7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000ig0jkroFE42_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '没有住到自己想住的房间（原已订房）办理入住时，碰到一个业务不熟的服务员（三间房办', '没有住到自己想住的房间（原已订房）办理入住时，碰到一个业务不熟的服务员（三间房办理了一个多小时）但还是没有办理完整的入住手续，给我们后续入住带来了很大的麻烦（餐饮房卡）', '2023-12-25', 3, '[''前台服务'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0232u12000cspo6di63B6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000cspxrbb7421_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000cspyh02ABF7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '为了满足父母情怀选择了这家老牌酒店，其实我是不喜欢住这种的，外国人不少，整个大堂', '为了满足父母情怀选择了这家老牌酒店，其实我是不喜欢住这种的，外国人不少，整个大堂叽叽呱呱的很吵，餐厅吃了性价比也是挺低的，味道并没有很惊艳', '2024-04-06', 3, '[''安静程度'', ''性价比'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231y12000dlmsumoAA64_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000dlmwr8778DC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236v12000dlmteb5F3D4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：老酒店但改造后还是一如既往舒适。', '设施：老酒店但改造后还是一如既往舒适。
卫生：干净。
环境：大堂一如既往的热闹，房间则安静。
服务：比以往增加了很多外籍员工，英语国语粤语切换自如，很有国际范。
其它∶泳池，干蒸超级点赞，早餐能吃到纳豆，是值得推荐的酒店。', '2023-12-08', 5, '[''整体满意度'', ''公共设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0200z12000cp3r530610C_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0234t12000cp3jh42A2C0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000cp3cr5a2D62_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000cp35h8xC0CD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一走进大厅，高端大气上档次，酒店还有一个博物馆，可以去逛逛，出行很方便，酒店出来', '一走进大厅，高端大气上档次，酒店还有一个博物馆，可以去逛逛，出行很方便，酒店出来就是地铁淘金站，总体感觉很不错', '2024-02-08', 5, '[''交通便利性'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230c12000d5qvdg4C77B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000d5qid7f9669_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236u12000d5quj3i164B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '真正的民旅品牌，超白金酒店。因为是在广交会期间，人山人海，但配备的服务员多，秩序', '真正的民旅品牌，超白金酒店。因为是在广交会期间，人山人海，但配备的服务员多，秩序井然。礼宾部的讲解人员小陈热情主动，认真讲解酒店的前世今生。由于外国人太多，酒店的香薰味太浓，引起嗓子不舒服，让前台经理把房间窗户打开通风，这才合适了。也巧，30楼的行政酒廊在这期间开放了，这两天躲在楼上看风景，喝下午茶，真是太好了。', '2023-10-31', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236m12000chhvslh4D2E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000chhwyhs019A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000chhwm6b002A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233z12000chhsf4bA25E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000chhr0ly8C3F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000chhyb8m1A67_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000chi2ccyCC78_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b12000chhu2ik4AFF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000chhw3r3C98F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务很好，室外花园很惬意！出来就有地铁站，对面就是友谊商店很方便', '酒店服务很好，室外花园很惬意！出来就有地铁站，对面就是友谊商店很方便', '2024-03-15', 5, '[''交通便利性'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234912000df5xagh64ED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000df5puhzF21B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c12000df5z7ayA321_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很干净', '房间很干净', '2024-07-02', 5, '[''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230s12000enga365D0D5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000engb0vm784F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000eng819z2E50_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '绝对大气的酒店！淘金地铁站出来步行三分钟就到，出行极方便。附近有广州酒家和点都德', '绝对大气的酒店！淘金地铁站出来步行三分钟就到，出行极方便。附近有广州酒家和点都德，还有糖水店，餐饮极方便。', '2024-02-01', 5, '[''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0231s12000d3odfmwDCF0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000d3oclcl2059_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间挺好的，酒店也很漂亮。但那天晚上半夜有人门口打电话吵到我睡觉了很不高兴。后来', '房间挺好的，酒店也很漂亮。但那天晚上半夜有人门口打电话吵到我睡觉了很不高兴。后来跟携程反馈了才处理好', '2024-04-22', 5, '[''安静程度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236z12000dqz6cpc16FD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000dqz5mfmB751_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '自带瀑布花园的宝藏酒店，大堂布满鲜花，巨幅红楼梦贴金壁画金碧辉煌，气派华贵；旋转', '自带瀑布花园的宝藏酒店，大堂布满鲜花，巨幅红楼梦贴金壁画金碧辉煌，气派华贵；旋转楼梯相当出片，后花园小桥流水，岩石飞瀑，体验感爆棚。', '2024-03-15', 4, '[''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232o12000df878rxF4B5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000df86ooaCC30_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230m12000df8614bC756_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000df86li9950B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000df85lxi88B7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '订之前好担心会设备陈旧，原来是我多虑了，值得下次再来', '订之前好担心会设备陈旧，原来是我多虑了，值得下次再来', '2024-03-18', 5, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232v12000dfybzy434A5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一批的白金五星酒店，设施虽然有些旧了，服务很好。如果晚上行政酒廊可以看到外面的', '第一批的白金五星酒店，设施虽然有些旧了，服务很好。如果晚上行政酒廊可以看到外面的夜景，因该更惬意哦。', '2024-01-27', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235312000d25srrq9817_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000d265loxDCC1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000d25oe5vC243_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233g12000d25nowf8452_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意的一次入住，酒店方面没有因为客人提出的房间升级而板着面孔加钱的要求？前台', '非常满意的一次入住，酒店方面没有因为客人提出的房间升级而板着面孔加钱的要求？前台小姐姐周到，耐心而且热情，尽量满足客人的需求，其实升级房型看似酒店损失，而实际上，客人的好评及口口相传比广告效益更好，这是格局长远的表现，看看前台办理入住的盛况？说明了酒店领导的眼光！感谢你们，我们还会再见！', '2023-11-10', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232g12000cjtzhhb2056_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232n12000cjttg5d1974_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务很好，订了三晚，后面两天给我升级了房型，非常感谢！酒店的花园和博物馆也很有看', '服务很好，订了三晚，后面两天给我升级了房型，非常感谢！酒店的花园和博物馆也很有看头，女儿很喜欢，天天要去逛花园', '2024-01-15', 5, '[''前台服务'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232r12000cy0eqbf6DBB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235112000cy0864a2927_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232312000cy0bvk6E9A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000cy0c1y41500_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000cy0ddly4353_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间重新装修过，还不错，就是浴缸摆放位置有点奇怪。初一早上有舞龙醒狮，很有氛围', '房间重新装修过，还不错，就是浴缸摆放位置有点奇怪。初一早上有舞龙醒狮，很有氛围', '2024-03-28', 5, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236512000diz05ky935E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店非常好，物有所值，餐厅也很好吃，服务人员态度都很好，入住的时候发小礼物和点心', '酒店非常好，物有所值，餐厅也很好吃，服务人员态度都很好，入住的时候发小礼物和点心，房间干净，隔音也好，可以说性价比相当高，就是淋浴在浴缸里的，我不太喜欢，要是可以分离就好了。体验了游泳池，还有免费的零食和冰淇淋。酒店总体的设施好得不得了，很多机组入住，国庆期间也有很多人办酒席，花园很漂亮，有博物馆。
自助早餐说实话非常一般，但水平比一般的酒店要好，主要还是外面的早茶太好吃了，一下子就把很普通的酒店自助餐比下去了。有30f旋转餐厅和大厅的瀑布餐厅可以选，旋转餐厅有点头晕，还挺热，建议还是瀑布餐厅吧。', '2023-11-06', 5, '[''性价比'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233t12000ciyh0lq968D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000ciygr14A011_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234h12000ciy85pgFAFB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店，开业38年，经久不衰，大堂永远人庭若市，伴随着悠扬的钢琴声，那么的和谐', '花园酒店，开业38年，经久不衰，大堂永远人庭若市，伴随着悠扬的钢琴声，那么的和谐高雅。此次专门接远道而归的家人，酒店的服务没有过分的热情，确也非常的周到和细致见内涵。房间由原定的红棉套房升级了到了新装修过的房型，床品舒适，床垫偏软，包裹性和承托性很好，一晚恬睡到天明。花园瀑布绿意盎然，锦鲤成群，是饭后的最佳去处。总体入住体验全家满意，值得再来。', '2023-10-30', 5, '[''整体满意度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231912000cheao36D0F0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000chef6024A95_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000ched5zk6D02_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000cheanx02A31_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236712000cheal6y898D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000chec5md9D68_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这个酒店是我在广州住过最舒服的酒店，位置好，服务好，早餐丰富，前台办理员nike', '这个酒店是我在广州住过最舒服的酒店，位置好，服务好，早餐丰富，前台办理员nike很漂亮，很是温柔，下次还住这里。', '2024-05-11', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233n12000dyi5cfr4344_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s12000dyi3qj19C46_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235t12000dyhtpx064CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237312000dyhytfs5488_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '干净，服务好', '干净，服务好', '2024-04-08', 5, '[''卫生状况'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233412000dmhi61241A1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净整洁。', '房间干净整洁。
服务：特别满意，有需求都能及时得到回应，服务特别好！酒店服务很用心！', '2024-01-26', 5, '[''卫生状况'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230r12000d1susqz5BAA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234212000d1ski7i88A2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次和家人到广州旅游，入住了广州花园酒店。在越秀区的花园酒店。正直广交会来往的顾', '这次和家人到广州旅游，入住了广州花园酒店。在越秀区的花园酒店。正直广交会来往的顾客非常的多，尤其外国人士占了将近50%。虽然入住率很高，但是花园酒店的服务也是跟得上，在广交会期间每层都有服务人员。问好，帮你排忧解难。虽然设施略显成就，但是作为亚洲第二个拥有旋转餐厅的酒店。总体还是非常的不错。', '2023-10-22', 4, '[''前台服务'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231j12000cfpnc0o787E_R_150_150_R5_Q70_D.webp\", \"https://dimg04.c-ctrip.com/images/0236512000cfpp1jp4075_R_150_150_R5_Q70_D.webp\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一如既往的好，每次来广州的必选酒店！', '一如既往的好，每次来广州的必选酒店！', '2024-03-05', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236b12000dckopkn6647_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店广州的白金五星酒店，前台服务也是白金五星，处处为宾客着想。岭南花园小桥流', '花园酒店广州的白金五星酒店，前台服务也是白金五星，处处为宾客着想。岭南花园小桥流水拍照打卡，四楼的酒店博物馆值得参观。', '2023-12-17', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234m12000cr1u4oxC2FD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000cr1q3rc8CAE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000cr1t43a6236_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000cr1s4mbAA54_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000cr1t937AE7A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意的，一如既往的喜欢。瀑布餐厅的早餐不错??整体服务态度真的可以', '非常满意的，一如既往的喜欢。瀑布餐厅的早餐不错??整体服务态度真的可以', '2024-01-30', 5, '[''餐饮设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232c12000d31r9ws83A1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '1. 【入住问题】入住排队等了几乎半个小时，从来没见过酒店前台效率这么低的；前台', '1. 【入住问题】入住排队等了几乎半个小时，从来没见过酒店前台效率这么低的；前台黑脸，没有微笑，不匹配酒店形象。完全是冲着品牌过来的，也住了很多次，反复多次提出过建议，没有任何改进。另外，前台和我们说升级到粤韵，结果发现是红棉，想换成粤韵，在房间打了一个小时电话都没有回复，令人恼火。
2. 【房间状态】红棉很旧，连中国大酒店这种低价酒店都比这个新，有点不可思议。喜欢这家酒店的粤韵，如果不订粤韵，其实这家酒店并没有那么值得居住，宁愿选择旁边的凯宾斯基酒店。我们经常住酒店，觉得花园酒店真的是人员服务匹配不上档次，能有预算选择白天鹅的话，还是选择白天鹅吧。
3. 【服务综评】这家酒店自从因为瀑布餐厅火了之后，管理素质一直跟不上来，甚至有服务人员不尊重客户的情况，不过副总经理和总经理态度尚在，不至于让人失望。但作为超过20年的老客户，真的为这家酒店的管理水平叹息。
ps.第一张和最后一张图是花园酒店，中间几张是旁边那一家酒店，真的对比好大……（??）?其实我们真的很喜欢花园酒店的，毕竟已经开了这么多年，当年做服装生意的时候也是在这里发家的，我们也有情怀，包括身边的朋友，也是有情怀却实在很难为之买单。今天的花园物是人非，除了公共区域之外，其他真的很难夸出口，也不想昧着良心来刷一个好评。??', '2023-11-20', 3, '[''前台服务'', ''退房/入住效率'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230m12000clvob1q68E8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231r12000clvujafC987_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u12000clvvqb444A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000clvnm0cCE97_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000clvo52jF28F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意住在花园酒店，帮我们升级了红棉大床房，房间有些旧但是都能满足需求，服务人', '非常满意住在花园酒店，帮我们升级了红棉大床房，房间有些旧但是都能满足需求，服务人员服务都很好，各方面都很满意。', '2023-12-22', 5, '[''整体满意度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234312000cs6f2apBA35_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000cs651eu624F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236a12000cs6cq42CA2A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233812000cs6682e59A5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231l12000cs6d5kc3898_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000cs6gfljD48C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000cs6c87j7EE7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235m12000cs6c87lC2F1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233g12000cs5zcqz0D66_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间中规中矩，毕竟是中国最早的五星级酒店之二，现代的设施该有的都有。外形和大堂的', '房间中规中矩，毕竟是中国最早的五星级酒店之二，现代的设施该有的都有。外形和大堂的挑高和巨幅壁画大观园让人震撼，中间藻井一条巨龙盘旋很是带气场，八台电梯足以让贝律铭大师的远见卓识得以认证。没感到岁月的蹉跎，维护得不错??。只是在办理入住和退房的时候稍感迟缓，需要等待多时才能办理好，但酒店不愧为国内五星级的黄埔军校，前台外语溜溜哒，耐心解释入住情况，可能也是办理迟缓的主要原因。住客多为老外，门童为巴基斯坦人，每个楼层都有服务员在电梯口恭候，特别感谢21楼服务员JoJo的热情接待，对问题反馈能及时解决。但酒店服务热线0号有时拨通了无人接听需要改进。小孩的洗漱用品没特别配备，有点遗憾。在旋转餐厅喝下午茶??时碰到了一个美籍华人，他告诉我自己常住花园酒店已有18年，虽然有天河一众奢华酒店，但他情有独钟，也是对酒店服务的认可，非常难得。', '2023-12-10', 5, '[''前台服务'', ''退房/入住效率'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236p12000cpmcy6s28C6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230p12000cpmc3fzF6C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q12000cpmcs9v40AC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店名符其实，地理位置优越，服务品质甚好！', '花园酒店名符其实，地理位置优越，服务品质甚好！', '2024-02-19', 5, '[''整体满意度'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231012000d8sj5s9A4F2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000d8seu0l3F98_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '进入金碧辉煌的大堂，眼睛一亮，一幅镶金壁画《红楼梦》值得赞叹！高大圣诞树烘托节日', '进入金碧辉煌的大堂，眼睛一亮，一幅镶金壁画《红楼梦》值得赞叹！高大圣诞树烘托节日气氛，前台服务特好，值得称赞。', '2023-12-15', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235r12000cqna9a51057_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000cqmzqqe51D7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000cqna9a91400_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231412000cqn61vsE720_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店环境很优美，入住很舒适，一旦反应问题就会及时处理和解决。', '广州花园酒店环境很优美，入住很舒适，一旦反应问题就会及时处理和解决。', '2024-01-30', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232812000d2urya07E03_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236l12000d2usir24AAF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231g12000d2un9jc35BB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间和服务都非常好，30楼的旋转餐厅非常给力，可以俯瞰整个广州城。健身房和游泳池', '房间和服务都非常好，30楼的旋转餐厅非常给力，可以俯瞰整个广州城。健身房和游泳池也很高级，真正是商务家庭出游的好住处', '2023-12-11', 5, '[''餐饮设施'', ''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235a12000cpq8r6a7507_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236812000cpq8r71C219_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u12000cpq8r7o6E6D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常幸运这次能够入住花园酒店，酒店的各方面都给我留下了特别美好的印象。不管是环境', '非常幸运这次能够入住花园酒店，酒店的各方面都给我留下了特别美好的印象。不管是环境还是服务，有其是餐饮，都是一流的。酒店大堂金碧辉煌，花园美轮美奂，各处鲜花环绕，细节都非常完美。太喜欢了！下次来广州一定选择再次入住。', '2023-10-08', 5, '[''整体满意度'', ''餐饮设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0201n12000ccsi6bj905A_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0235f12000ccscv5l7647_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231612000ccsfrin8247_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000ccsgjc8EB68_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次出行广州入住了老花园酒店，酒店服务、美食、园林布局果然名不虚传，很有老牌白金', '这次出行广州入住了老花园酒店，酒店服务、美食、园林布局果然名不虚传，很有老牌白金五星酒店的风范，较有底蕴。出行前每次致电酒店都有宾至如归的感觉，check in入住当天Viria的专业态度和贴心服务更是留下了深刻印象；瀑布餐厅的景观、荔湾艇的晚餐、行政走廊的早餐都不妨一试。', '2023-10-09', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235e12000ccy2ltx7E33_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232512000ccyagow6D4C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000ccy8x2cA2B3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000ccy873427DD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000ccy2lu10670_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常棒的体验～完全没得挑', '非常棒的体验～完全没得挑
从办理入住到离开每天都是开心的～', '2024-02-05', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231z12000d4vj6f7EAFC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230m12000d4w5l8s622C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间蛮新的，重新装修，不是想象中很老的破五星，大堂特别气派，关键酒店里吃货的天堂', '房间蛮新的，重新装修，不是想象中很老的破五星，大堂特别气派，关键酒店里吃货的天堂，二楼荔湾亭早茶及中晚餐味道很好，三楼桃园馆是米其林餐厅，做的色香味俱全，很细腻，味道很好！一定要品尝，吃了对面广州酒家后觉得还是酒店里好吃！连住三晚！', '2023-10-05', 5, '[''餐饮设施'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231y12000cc5dst20A76_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000cc5fo616389_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000cc5bnzh1749_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000cc5a3cp7517_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000cc5fzlf1E4F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236v12000cc5bqkm1AD8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000cc5ckr8CD31_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000cc5g3n5692C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000cc5ethg82F3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '感谢酒店再一次给我们升级到粤韵房。感谢！酒店各方面都很棒！很美好的入住体验。今后', '感谢酒店再一次给我们升级到粤韵房。感谢！酒店各方面都很棒！很美好的入住体验。今后还会选择，期待下次还能有美好的经历！谢谢！', '2023-11-30', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230f12000cnp8n7n1D08_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000cnp82cqA119_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000cnp8gdy704C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235y12000cnp71099458_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店住的特别舒服 早餐丰富 下次来还住这里', '酒店住的特别舒服 早餐丰富 下次来还住这里', '2024-02-12', 5, '[''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231n12000d6psmwzC0B6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233612000d6p96cv851C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236812000d6p54g4DF1A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000d6por8n31E6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000d6pph9c080F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000d6pmgxkE3C2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000d6pqyls78B7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232k12000d6pbyug0595_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000d6pplk5CACF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '被白金五星给骗了，本来以为是贝聿铭设计的，想来体验一下。然后一进房间就是一股很浓', '被白金五星给骗了，本来以为是贝聿铭设计的，想来体验一下。然后一进房间就是一股很浓的发霉味道。晚上发现原来一洗澡地板就会漏水。然后房间窗户是封闭式的，很本不通风，所以浓浓的霉味。特别不满意，住到现在最差的五星。', '2023-10-07', 1, '[''房间设施'', ''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0202p12000cck321v2534_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0236y12000cck1jdkF6D3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '太惊艳了，果然没有选错。白金级的服务超赞。除了酒店环境无可挑剔、后花园内的岭南景', '太惊艳了，果然没有选错。白金级的服务超赞。除了酒店环境无可挑剔、后花园内的岭南景物让人难忘。入住时送了水果。打卡点后送了文创小物。哈哈哈??开心。', '2023-11-08', 5, '[''前台服务'', ''整体满意度'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0233t12000cjb9j5gC35A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000cjb5nv136C6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000cjb85eeEA16_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000cjbb14006BB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234s12000cjbebxpDAAC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233g12000cjbe0tr964E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000cjbeu9dBE15_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000cjbbycg6BE2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234g12000cjbgoesAC7F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '粤韵双床房非常舒适，64平米，适合一家三口入住，晚上小朋友睡觉后还可以在客厅独立', '粤韵双床房非常舒适，64平米，适合一家三口入住，晚上小朋友睡觉后还可以在客厅独立的空间看书或看剧。老牌五星酒店，房间隔断做得很好，隔音效果不错。另外，酒店餐厅也很值得打卡，荔湾亭性价比相对高。', '2023-10-02', 5, '[''房间设施'', ''安静程度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232b12000cazzlocAE89_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '各方面都不错', '各方面都不错', '2024-03-07', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230w12000dd3pmtsCF1D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000dd41a25148D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000dd3xskhD038_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000dd3y7l929D8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '开了三间房，两间出问题。', '开了三间房，两间出问题。
第一间：
1.1房卡日期设置错误，无法开房门，下去前台，问我们是否续住的，最后前台解释说日期设置错，是上位前台开卡失误。
1.2入住登记时，已提出要求把三间作关联，因为前台为了快速处理入住，没有告知房卡分别用了谁的信息登记，导致重新开卡时的误会，第一次增加了与前台沟通成本，因为原接待的前台走开了。

第二间：
2.1门锁措施残旧未更换。刷卡进房，门锁显示灯为绿色，但扭动无效，喊了在隔壁的房务员，几次也开不了。
2.2服务响应速度慢。通过楼层电话直拨客服中心，如上反应情况，因为1.2中不知道房卡登记谁的信息，对方也不直接说我信息错误，来回间第二次增加了沟通成本，核对好信息，对方表示让礼宾的同事上来，耐心等待了十来分钟，再次拨打电话，对方表示已看到礼宾员上来找我们，再次耐心等待，才等来礼宾员。
2.3升级房间失误。礼宾员试过门后，主动提出升级房间，并为我们换房卡并带我们去新的房间，我们再再次耐心等待，结果新的房间是双人房，原来房间是大床。礼宾员电话叫房务员拿卡开隔壁房，然后我们再再再次耐心等待，房间没错了。
2.4突**况无备注。礼宾下去换卡给我们，我们婉言拒绝，因为原定外出的时间已耽误很久了，只能晚上我们自己去前台拿卡，让帮忙开好卡就行。晚上回来报了新房号给前台，前台一脸懵，但他并没有表明问题所在，又是一次次无效沟通，他也不停地点击鼠标，我们再再再再次耐心等待，最后我把入住到之前的说了，并主动说了三位入住信息，他才说“难怪和登记的不一样”，第三次增加沟通成本。然而新的房间根本没有为我们预留，也没有任何注明，好在没开出去，不然都不用睡了。
2.5基础专业失误。开好房卡后，前台主动提出带我们到房间，以防其他情况发生。结果房卡刷不开门，显示灯是红色。我们再再再再再次耐心等待前台重新开卡。
最后要赞一下的。唯一一间没有任何问题的，是我爸妈入住的，对大堂工作人员很满意，主动服务意识非常强，房间也很宽敞舒适，对第三次入住花园酒店，仍然是非常满意。真的很谢谢，再再再再再再次感谢', '2023-09-21', 1, '[''前台服务'', ''退房/入住效率'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231h12000c7cs670D9E0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000c7d14wd4F35_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235p12000c7cx9m08E42_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236g12000c7d3aa326D8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '目前住过广州最有特色的酒店，整个酒店就像一间巨大的博物馆??就很有历史底蕴，酒店', '目前住过广州最有特色的酒店，整个酒店就像一间巨大的博物馆??就很有历史底蕴，酒店的外国友人也很多。本来以为这么老的酒店，只是住个特色，没想到真正住下来很惊喜。床品软硬适中，让人一躺下来就想睡觉。', '2023-09-22', 5, '[''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233f12000c7ruvp46DC5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000c7s31fu2F57_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000c7s3kdwF242_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230t12000c7rymqkAC63_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000c7s2s215E1B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000c7s32emD380_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234o12000c7s1jgtA717_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234612000c7s2geq14B1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236u12000c7rsy6y540B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '首先我想说.一直出差来广州.住过很多家酒店.但是对于我这个挑剔的人来说.我很喜欢', '首先我想说.一直出差来广州.住过很多家酒店.但是对于我这个挑剔的人来说.我很喜欢花园酒店.品牌有文化底蕴.尤其是吃早饭下午茶的瀑布酒店很漂亮.装修风格干净典雅.服务也很好.让你心里舒服.停车在隔壁的地下停车场也很方便.总之希望继续保持哦.以后只要来广州就是花园酒店！', '2023-09-15', 5, '[''整体满意度'', ''餐饮设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230e12000c5h2u95A728_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000c5grlf4CE05_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000c5h4x3aA0E2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000c5gtqasC300_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231b12000c5gtqau9F82_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台Katherine、Gtillian小姐姐服务态度非常不错，专门给她的好评。', '前台Katherine、Gtillian小姐姐服务态度非常不错，专门给她的好评。交通便利，停车方便!停车场很大，还是免费停车场。房间很大，设施也很齐全。房间还送的有矿泉水。前台小姐姐估计是考虑我要休养，给我升级了房型一房一厅高楼层真是太舒服了！床上用品洗的也很干净，床垫软软的，睡起来很舒服。中央空调很凉快。有什么需要，给前台打电话，都能解决!前台小姐姐还详细的讲解了吗无线网，早餐种类等!真的很好！', '2023-09-13', 5, '[''前台服务'', ''交通便利性'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231n12000c4hb8yn5177_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000c4hg3ez3316_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000c4he5ug2B02_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：一流和先进。', '设施：一流和先进。
卫生：干净。
环境：优美、静谧。
服务：到位。大堂部服务员James Mancy的服务态度热情，主动帮我升级房型。客房部经理Echo主动关心我住的怎么样。
广州花园酒店真是好！还想再住一次。', '2024-08-28', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232412000fa9f49b0BFB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000fa9l5ckC632_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230v12000fa9wbv02FAE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232k12000fa9dtbfBE0E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很棒的酒店，下次来广州会首先考虑，花园非常漂亮', '很棒的酒店，下次来广州会首先考虑，花园非常漂亮', '2024-01-17', 5, '[''整体满意度'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0235c12000cyhtfp1D3BE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000cyht0s50C3E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000cyhtkrd2188_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '住的很舒服，服务很好，房间干净，还给升级了房间', '住的很舒服，服务很好，房间干净，还给升级了房间', '2024-01-16', 5, '[''整体满意度'', ''客房服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235u12000cy3sgih6B9B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231d12000cy3vgvc5BE7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000cy3rlf545E4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236s12000cy3wnfg5F58_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000cy451uuCD3B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000cy3eatp1F2A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000cy47j8g6E5D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000cy480r25945_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施齐全园林景观很好', '设施齐全园林景观很好', '2024-03-15', 5, '[''公共设施'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0234a12000df7ldbp049A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店，完完全全颠覆了我的感知，－个长达38年的白金五星级酒店保养的如此完美！', '花园酒店，完完全全颠覆了我的感知，－个长达38年的白金五星级酒店保养的如此完美！醉了！！！
酒店的硬件不说，它的专业程度更让我敬佩，从前台，到锦鲤行政酒廊，再到自助餐厅，佩服佩服，这一切让我连住四晚，真真切切体验了并亨受着，在此感谢花园酒店，感谢花园酒店的员工，更要感谢Getting.和Getting.和Bettg谢谢你们了感受了你们专业，优秀，传承了花园酒店的优良传统，再次感谢，
